function cleanHtml(html) {
  return html
    .replace(/<br\s*\/?>/gi, "\n")
    .replace(/<\/?(p|div|span|font|b|strong|em|td)[^>]*>/gi, " ")
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, "")
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, "")
    .replace(/<[^>]+>/g, "")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/\s+/g, " ")
    .trim();
}

const bodyHtml = $json.body?.content || "";
const subject = $json.subject || "";
const body = cleanHtml(bodyHtml);

const result = {};

// --------------------------------------------------
// Extract AWS Account ID
// --------------------------------------------------
const accMatch =
  subject.match(/AWS Account:\s*(\d{6,})/i) ||
  body.match(/Affected account\s+(\d{6,})/i);

result.accountId = accMatch ? accMatch[1] : "Unknown";

// --------------------------------------------------
// Extract GENERALIZED EVENT TITLE (PARENT SUMMARY)
// --------------------------------------------------
// Remove account + region noise from subject
result.eventTitle = subject
  .replace(/\[AWS Account:.*?\]/gi, "")
  .replace(/\[[A-Z0-9-]+\]/gi, "")
  .replace(/^\[Action Required\]\s*/i, "")
  .trim() || "AWS Health Event";

// --------------------------------------------------
// Extract DEADLINE / DATE (if present)
// --------------------------------------------------
const dateMatch = body.match(
  /(January|February|March|April|May|June|July|August|September|October|November|December)\s+\d{1,2},\s+\d{4}/i
);

result.deadline = dateMatch ? dateMatch[0] : "Not specified";

// --------------------------------------------------
// Extract GENERAL DESCRIPTION (PARENT DESCRIPTION)
// --------------------------------------------------
const generalDescMatch = body.match(
  /(Our records indicate.*?end of support.*?\.)/i
);

result.parentDescription = generalDescMatch
  ? generalDescMatch[1].trim()
  : "General AWS Health notification regarding this event.";

// --------------------------------------------------
// Extract ACCOUNT-SPECIFIC ACTION (SUBTASK DESCRIPTION)
// --------------------------------------------------
const actionMatch = body.match(
  /(We recommend that you.*?)(If you have any questions|$)/i
);

result.subtaskDescription = actionMatch
  ? actionMatch[1].trim()
  : "Review AWS Health Dashboard and take recommended action.";

// --------------------------------------------------
// Build UNIQUE EVENT KEY (for parent dedupe)
// --------------------------------------------------
result.eventKey = result.eventTitle.toLowerCase().replace(/\s+/g, "-");

// --------------------------------------------------
// Build JIRA SUMMARIES (NEW MODEL)
// --------------------------------------------------
result.parentSummary = result.eventTitle;

result.subtaskSummary =
  `AWS Account: ${result.accountId}` +
  (result.deadline !== "Not specified"
    ? ` – ${result.deadline}`
    : "");

// --------------------------------------------------
// Build JIRA DESCRIPTIONS
// --------------------------------------------------
result.parentJiraDescription = `
*AWS Health – General Event*

${result.parentDescription}

*Deadline*
${result.deadline}
`.trim();

result.subtaskJiraDescription = `
*Affected AWS Account*
${result.accountId}

*Required Action*
${result.subtaskDescription}

*Deadline*
${result.deadline}
`.trim();

return result;

